-- BEGIN items/effects/evd_item_effect_abyss_ticket_use.sql
create or replace function public.evd_item_effect_abyss_ticket_use(
    p_run_id uuid,
    p_user_id text,
    p_account_name text,
    p_current_floor integer,
    p_max_floors integer,
    p_generation_profile_id uuid
)
returns jsonb
language plpgsql
as $$
declare
    v_bonus_sum integer := 0;
    v_target_floor integer := least(p_current_floor + 3, p_max_floors);
    v_shift_count integer := greatest(v_target_floor - p_current_floor, 0);
begin
    select coalesce(sum(fbp.bonus_coins), 0)
      into v_bonus_sum
      from public.evd_floor_bonus_profiles fbp
     where fbp.profile_id = p_generation_profile_id
       and fbp.floor_no > p_current_floor
       and fbp.floor_no <= v_target_floor;

    update public.evd_game_runs
       set run_coins = run_coins + v_bonus_sum,
           floor_bonus_total = floor_bonus_total + v_bonus_sum
     where id = p_run_id;

    perform public.evd_resolve_floor_shift(p_run_id, p_user_id, v_target_floor, 'ラン中');
    perform public.evd_add_log(
        p_run_id,
        p_user_id,
        p_account_name,
        v_target_floor,
        'アイテム使用',
        format('奈落の切符で %s 階層進み、ボーナス %s coin を獲得した。', v_shift_count, v_bonus_sum)
    );

    return jsonb_build_object(
        'should_consume', true,
        'finish_run', false
    );
end;
$$;
-- END items/effects/evd_item_effect_abyss_ticket_use.sql

-- BEGIN items/effects/evd_item_effect_golden_contract_settle_escape.sql
create or replace function public.evd_item_effect_golden_contract_settle_escape(
    p_inventory_state jsonb,
    p_run_coins integer,
    p_secured_coins integer,
    p_final_return_multiplier numeric
)
returns jsonb
language plpgsql
as $$
declare
    v_items jsonb := coalesce(p_inventory_state -> 'items', '{}'::jsonb);
    v_flags jsonb := coalesce(p_inventory_state -> 'flags', '{}'::jsonb);
    v_qty integer := greatest(
        coalesce((v_items -> 'golden_contract' ->> 'quantity')::integer, 0),
        case when coalesce((v_flags ->> 'golden_contract_active')::boolean, false) then 1 else 0 end
    );
    v_inventory jsonb := p_inventory_state;
begin
    if v_qty <= 0 then
        return jsonb_build_object(
            'eligible', false,
            'payout', null,
            'inventory_state', p_inventory_state
        );
    end if;

    if coalesce((v_items -> 'golden_contract' ->> 'quantity')::integer, 0) > 0 then
        v_inventory := public.evd_remove_item(v_inventory, 'golden_contract', 1);
    end if;

    return jsonb_build_object(
        'eligible', true,
        'payout', floor((p_run_coins + p_secured_coins) * (p_final_return_multiplier + 1.0))::integer,
        'inventory_state', v_inventory,
        'consumed_effect', 'golden_contract'
    );
end;
$$;
-- END items/effects/evd_item_effect_golden_contract_settle_escape.sql

-- BEGIN items/effects/evd_item_effect_return_multiplier_bonus_on_escape_settle_escape.sql
create or replace function public.evd_item_effect_return_multiplier_bonus_on_escape_settle_escape(
    p_inventory_state jsonb,
    p_run_coins integer,
    p_secured_coins integer,
    p_final_return_multiplier numeric
)
returns jsonb
language plpgsql
as $$
declare
    v_items jsonb := coalesce(p_inventory_state -> 'items', '{}'::jsonb);
    v_qty integer := coalesce((v_items -> 'return_blessing' ->> 'quantity')::integer, 0);
    v_amount numeric(10, 4) := 1.0;
    v_multiplier numeric(10, 4) := 1.0;
    v_inventory jsonb := p_inventory_state;
begin
    if v_qty <= 0 then
        return jsonb_build_object(
            'eligible', false,
            'payout', null,
            'inventory_state', p_inventory_state
        );
    end if;

    select coalesce((effect_data ->> 'amount')::numeric, 1.0)
      into v_amount
      from public.evd_item_catalog
     where code = 'return_blessing';

    v_multiplier := power(greatest(v_amount, 1.0), v_qty);
    v_inventory := public.evd_remove_item(v_inventory, 'return_blessing', v_qty);

    return jsonb_build_object(
        'eligible', true,
        'payout', floor((p_run_coins + p_secured_coins) * p_final_return_multiplier * v_multiplier)::integer,
        'inventory_state', v_inventory,
        'consumed_effect', 'return_multiplier_bonus_on_escape'
    );
end;
$$;
-- END items/effects/evd_item_effect_return_multiplier_bonus_on_escape_settle_escape.sql

