-- BEGIN items/effects/evd_item_effect_insurance_settle_death.sql
create or replace function public.evd_item_effect_insurance_settle_death(
    p_inventory_state jsonb
)
returns jsonb
language plpgsql
as $$
declare
    v_flags jsonb := coalesce(p_inventory_state -> 'flags', '{}'::jsonb);
    v_inventory jsonb := p_inventory_state;
    v_active boolean := coalesce((v_flags ->> 'insurance_active')::boolean, false);
begin
    if not v_active then
        return jsonb_build_object(
            'eligible', false,
            'base_rate', null,
            'inventory_state', p_inventory_state
        );
    end if;

    v_flags := jsonb_set(v_flags, array['insurance_active'], 'false'::jsonb, true);
    v_inventory := jsonb_set(v_inventory, array['flags'], v_flags, true);

    return jsonb_build_object(
        'eligible', true,
        'base_rate', 0.50,
        'inventory_state', v_inventory
    );
end;
$$;
-- END items/effects/evd_item_effect_insurance_settle_death.sql

-- BEGIN items/effects/evd_item_effect_relic_shop_discount_plus_5pct_collect.sql
create or replace function public.evd_item_effect_relic_shop_discount_plus_5pct_collect(
    p_modifiers jsonb,
    p_quantity integer
)
returns jsonb
language plpgsql
as $$
declare
    v_current numeric := coalesce((p_modifiers ->> 'shop_discount_rate')::numeric, 0);
begin
    return jsonb_set(
        p_modifiers,
        array['shop_discount_rate'],
        to_jsonb(least(0.20::numeric, v_current + (greatest(p_quantity, 0) * 0.05))),
        true
    );
end;
$$;
-- END items/effects/evd_item_effect_relic_shop_discount_plus_5pct_collect.sql

-- BEGIN items/effects/evd_item_effect_relic_carry_limit_plus_1_collect.sql
create or replace function public.evd_item_effect_relic_carry_limit_plus_1_collect(
    p_modifiers jsonb,
    p_quantity integer
)
returns jsonb
language plpgsql
as $$
begin
    if greatest(p_quantity, 0) <= 0 then
        return p_modifiers;
    end if;

    return jsonb_set(
        p_modifiers,
        array['carry_limit_bonus'],
        to_jsonb(1),
        true
    );
end;
$$;
-- END items/effects/evd_item_effect_relic_carry_limit_plus_1_collect.sql

-- BEGIN items/effects/evd_item_effect_relic_return_multiplier_plus_0_05_collect.sql
create or replace function public.evd_item_effect_relic_return_multiplier_plus_0_05_collect(
    p_modifiers jsonb,
    p_quantity integer
)
returns jsonb
language plpgsql
as $$
declare
    v_current numeric := coalesce((p_modifiers ->> 'return_multiplier_bonus')::numeric, 0);
begin
    return jsonb_set(
        p_modifiers,
        array['return_multiplier_bonus'],
        to_jsonb(v_current + (least(greatest(p_quantity, 0), 4) * 0.05)),
        true
    );
end;
$$;
-- END items/effects/evd_item_effect_relic_return_multiplier_plus_0_05_collect.sql

