-- BEGIN items/dispatch/evd_dispatch_apply_granted_item.sql
create or replace function public.evd_dispatch_apply_granted_item(
    p_inventory jsonb,
    p_item_code text
)
returns jsonb
language plpgsql
as $$
declare
    v_effect text;
begin
    select effect_data ->> 'effect'
      into v_effect
      from public.evd_item_catalog
     where code = p_item_code;

    case v_effect
        when 'substitute' then
            return public.evd_item_effect_substitute_apply(p_inventory, p_item_code);
        when 'insurance' then
            return public.evd_item_effect_insurance_apply(p_inventory, p_item_code);
        when 'golden_contract' then
            return public.evd_item_effect_golden_contract_apply(p_inventory, p_item_code);
        when 'vault_box' then
            return public.evd_item_effect_vault_box_apply(p_inventory, p_item_code);
        else
            return public.evd_add_item(p_inventory, p_item_code, 1);
    end case;
end;
$$;
-- END items/dispatch/evd_dispatch_apply_granted_item.sql

-- BEGIN items/dispatch/evd_collect_passive_modifiers.sql
create or replace function public.evd_collect_passive_modifiers(
    p_user_id text
)
returns jsonb
language plpgsql
as $$
declare
    v_stock record;
    v_modifiers jsonb := jsonb_build_object(
        'carry_limit_bonus', 0,
        'return_multiplier_bonus', 0,
        'shop_discount_rate', 0,
        'always_bomb_radar', false,
        'max_life_bonus', 0,
        'death_coin_keep_bonus', 0,
        'keep_unused_manual_on_death', false
    );
begin
    for v_stock in
        select
            st.item_code,
            st.quantity,
            c.effect_data ->> 'effect' as effect_name
          from public.evd_player_item_stocks st
          join public.evd_item_catalog c
            on c.code = st.item_code
         where st.user_id = p_user_id
           and st.quantity > 0
           and c.is_active = true
    loop
        case v_stock.effect_name
            when 'relic_shop_discount_plus_5pct' then
                v_modifiers := public.evd_item_effect_relic_shop_discount_plus_5pct_collect(v_modifiers, v_stock.quantity);
            when 'relic_carry_limit_plus_1' then
                v_modifiers := public.evd_item_effect_relic_carry_limit_plus_1_collect(v_modifiers, v_stock.quantity);
            when 'relic_return_multiplier_plus_0_05' then
                v_modifiers := public.evd_item_effect_relic_return_multiplier_plus_0_05_collect(v_modifiers, v_stock.quantity);
            when 'relic_bomb_radar_always' then
                v_modifiers := public.evd_item_effect_relic_bomb_radar_always_collect(v_modifiers, v_stock.quantity);
            when 'relic_max_life_plus_1' then
                v_modifiers := public.evd_item_effect_relic_max_life_plus_1_collect(v_modifiers, v_stock.quantity);
            when 'relic_death_coin_keep_plus_2pct' then
                v_modifiers := public.evd_item_effect_relic_death_coin_keep_plus_2pct_collect(v_modifiers, v_stock.quantity);
            when 'relic_keep_unused_manual_on_death' then
                v_modifiers := public.evd_item_effect_relic_keep_unused_manual_on_death_collect(v_modifiers, v_stock.quantity);
        end case;
    end loop;

    return v_modifiers;
end;
$$;
-- END items/dispatch/evd_collect_passive_modifiers.sql

-- BEGIN items/dispatch/evd_dispatch_use_item.sql
create or replace function public.evd_dispatch_use_item(
    p_run_id uuid,
    p_user_id text,
    p_account_name text,
    p_current_floor integer,
    p_max_floors integer,
    p_generation_profile_id uuid,
    p_item_code text
)
returns jsonb
language plpgsql
as $$
declare
    v_effect_data jsonb := '{}'::jsonb;
    v_effect text;
begin
    select coalesce(effect_data, '{}'::jsonb), effect_data ->> 'effect'
      into v_effect_data, v_effect
      from public.evd_item_catalog
     where code = p_item_code;

    case v_effect
        when 'escape_run' then
            return public.evd_item_effect_escape_rope_use(p_run_id, p_user_id, p_account_name, p_current_floor);
        when 'bomb_radar' then
            return public.evd_item_effect_bomb_radar_use(p_item_code);
        when 'reveal_stairs' then
            return public.evd_item_effect_reveal_stairs_use(p_run_id, p_user_id, p_account_name, p_current_floor);
        when 'reveal_hazards' then
            return public.evd_item_effect_reveal_hazards_use(p_run_id, p_user_id, p_account_name, p_current_floor);
        when 'reveal_bombs' then
            return public.evd_item_effect_reveal_bombs_use(p_run_id, p_user_id, p_account_name, p_current_floor);
        when 'increase_max_hp_full_restore' then
            return public.evd_item_effect_holy_grail_use(p_run_id, p_user_id, p_account_name, p_current_floor);
        when 'advance_floor_with_bonus' then
            return public.evd_item_effect_abyss_ticket_use(p_run_id, p_user_id, p_account_name, p_current_floor, p_max_floors, p_generation_profile_id);
        when 'heal_hp' then
            return public.evd_item_effect_heal_hp_use(p_run_id, p_user_id, p_account_name, p_current_floor, v_effect_data);
        when 'increase_max_hp' then
            return public.evd_item_effect_increase_max_hp_use(p_run_id, p_user_id, p_account_name, p_current_floor, v_effect_data);
        else
            raise exception 'このアイテムは使用できません: %', p_item_code;
    end case;
end;
$$;
-- END items/dispatch/evd_dispatch_use_item.sql

-- BEGIN items/dispatch/evd_dispatch_finish_run_escape_settlement.sql
create or replace function public.evd_dispatch_finish_run_escape_settlement(
    p_inventory_state jsonb,
    p_run_coins integer,
    p_secured_coins integer,
    p_final_return_multiplier numeric
)
returns jsonb
language plpgsql
as $$
declare
    v_base_result jsonb;
    v_golden_result jsonb;
    v_blessing_result jsonb;
    v_base_payout integer;
    v_golden_payout integer;
    v_blessing_payout integer;
begin
    v_base_payout := floor((p_run_coins + p_secured_coins) * p_final_return_multiplier)::integer;
    v_base_result := jsonb_build_object(
        'payout', v_base_payout,
        'inventory_state', p_inventory_state,
        'selected_effect', null
    );

    v_golden_result := public.evd_item_effect_golden_contract_settle_escape(
        p_inventory_state,
        p_run_coins,
        p_secured_coins,
        p_final_return_multiplier
    );
    v_blessing_result := public.evd_item_effect_return_multiplier_bonus_on_escape_settle_escape(
        p_inventory_state,
        p_run_coins,
        p_secured_coins,
        p_final_return_multiplier
    );

    v_golden_payout := coalesce((v_golden_result ->> 'payout')::integer, -1);
    v_blessing_payout := coalesce((v_blessing_result ->> 'payout')::integer, -1);

    if coalesce((v_golden_result ->> 'eligible')::boolean, false)
       and v_golden_payout >= greatest(v_base_payout, v_blessing_payout) then
        return jsonb_build_object(
            'payout', v_golden_payout,
            'inventory_state', v_golden_result -> 'inventory_state',
            'selected_effect', v_golden_result ->> 'consumed_effect'
        );
    end if;

    if coalesce((v_blessing_result ->> 'eligible')::boolean, false)
       and v_blessing_payout > v_base_payout then
        return jsonb_build_object(
            'payout', v_blessing_payout,
            'inventory_state', v_blessing_result -> 'inventory_state',
            'selected_effect', v_blessing_result ->> 'consumed_effect'
        );
    end if;

    return v_base_result;
end;
$$;
-- END items/dispatch/evd_dispatch_finish_run_escape_settlement.sql

-- BEGIN items/dispatch/evd_dispatch_finish_run_death_settlement.sql
create or replace function public.evd_dispatch_finish_run_death_settlement(
    p_user_id text,
    p_inventory_state jsonb,
    p_run_coins integer,
    p_secured_coins integer
)
returns jsonb
language plpgsql
as $$
declare
    v_modifiers jsonb := public.evd_collect_passive_modifiers(p_user_id);
    v_vault_result jsonb;
    v_insurance_result jsonb;
    v_inventory_state jsonb := p_inventory_state;
    v_base_rate numeric(8, 4) := 0.0;
    v_wallet_bonus numeric(8, 4) := coalesce((v_modifiers ->> 'death_coin_keep_bonus')::numeric, 0.0);
    v_has_coffin boolean := coalesce((v_modifiers ->> 'keep_unused_manual_on_death')::boolean, false);
    v_death_return_rate numeric(8, 4);
    v_payout integer;
begin
    v_vault_result := public.evd_item_effect_vault_box_settle_death(p_inventory_state);
    v_insurance_result := public.evd_item_effect_insurance_settle_death(p_inventory_state);

    if coalesce((v_vault_result ->> 'eligible')::boolean, false) then
        v_base_rate := coalesce((v_vault_result ->> 'base_rate')::numeric, 0.80);
        v_inventory_state := coalesce(v_vault_result -> 'inventory_state', p_inventory_state);
    elsif coalesce((v_insurance_result ->> 'eligible')::boolean, false) then
        v_base_rate := coalesce((v_insurance_result ->> 'base_rate')::numeric, 0.50);
        v_inventory_state := coalesce(v_insurance_result -> 'inventory_state', p_inventory_state);
    end if;

    v_death_return_rate := least(1.0, coalesce(v_base_rate, 0.0) + coalesce(v_wallet_bonus, 0.0));
    v_payout := p_secured_coins + floor(p_run_coins * v_death_return_rate)::integer;

    return jsonb_build_object(
        'payout', greatest(v_payout, 0),
        'inventory_state', v_inventory_state,
        'has_coffin', v_has_coffin,
        'death_return_rate', v_death_return_rate
    );
end;
$$;
-- END items/dispatch/evd_dispatch_finish_run_death_settlement.sql

-- BEGIN items/dispatch/evd_validate_item_effect_registry.sql
create or replace function public.evd_validate_item_effect_registry()
returns table (
    issue_type text,
    item_code text,
    effect_name text,
    detail text
)
language sql
as $$
    with active_items as (
        select
            code,
            effect_data ->> 'effect' as effect_name,
            item_kind
          from public.evd_item_catalog
         where is_active = true
    ),
    granted_item_effects as (
        select unnest(array['substitute','insurance','golden_contract','vault_box']) as effect_name
    ),
    passive_modifier_effects as (
        select unnest(array[
            'relic_shop_discount_plus_5pct',
            'relic_carry_limit_plus_1',
            'relic_return_multiplier_plus_0_05',
            'relic_bomb_radar_always',
            'relic_max_life_plus_1',
            'relic_death_coin_keep_plus_2pct',
            'relic_keep_unused_manual_on_death'
        ]) as effect_name
    ),
    automatic_runtime_effects as (
        select unnest(array[
            'revive_on_death',
            'heal_hp_on_floor_advance',
            'add_coin_on_coin_pickup'
        ]) as effect_name
    ),
    use_item_effects as (
        select unnest(array[
            'escape_run',
            'bomb_radar',
            'reveal_stairs',
            'reveal_hazards',
            'reveal_bombs',
            'heal_hp',
            'increase_max_hp',
            'increase_max_hp_full_restore',
            'advance_floor_with_bonus'
        ]) as effect_name
    ),
    settlement_escape_effects as (
        select unnest(array['golden_contract','return_multiplier_bonus_on_escape']) as effect_name
    ),
    settlement_death_effects as (
        select unnest(array['vault_box','insurance','relic_death_coin_keep_plus_2pct','relic_keep_unused_manual_on_death']) as effect_name
    )
    select
        'missing_use_item_handler' as issue_type,
        ai.code as item_code,
        ai.effect_name,
        'manual item is active but not registered in use-item dispatcher' as detail
      from active_items ai
     where ai.item_kind = '手動'
       and not exists (select 1 from use_item_effects uie where uie.effect_name = ai.effect_name)
    union all
    select
        'missing_settlement_escape_handler' as issue_type,
        ai.code as item_code,
        ai.effect_name,
        'escape settlement effect is active but not registered in finish-run escape dispatcher' as detail
      from active_items ai
     where ai.effect_name in ('golden_contract','return_multiplier_bonus_on_escape')
       and not exists (select 1 from settlement_escape_effects see where see.effect_name = ai.effect_name)
    union all
    select
        'missing_settlement_death_handler' as issue_type,
        ai.code as item_code,
        ai.effect_name,
        'death settlement effect is active but not registered in finish-run death dispatcher' as detail
      from active_items ai
     where ai.effect_name in ('vault_box','insurance','relic_death_coin_keep_plus_2pct','relic_keep_unused_manual_on_death')
       and not exists (select 1 from settlement_death_effects sde where sde.effect_name = ai.effect_name)
    union all
    select
        'unimplemented_effect' as issue_type,
        ai.code as item_code,
        ai.effect_name,
        'effect is active in catalog but no known phase registry includes it' as detail
      from active_items ai
     where coalesce(ai.effect_name, '') <> ''
       and not exists (select 1 from granted_item_effects gie where gie.effect_name = ai.effect_name)
       and not exists (select 1 from passive_modifier_effects pme where pme.effect_name = ai.effect_name)
       and not exists (select 1 from automatic_runtime_effects aref where aref.effect_name = ai.effect_name)
       and not exists (select 1 from use_item_effects uie where uie.effect_name = ai.effect_name)
       and not exists (select 1 from settlement_escape_effects see where see.effect_name = ai.effect_name)
       and not exists (select 1 from settlement_death_effects sde where sde.effect_name = ai.effect_name)
    union all
    select
        'duplicate_active_item_code' as issue_type,
        c.code as item_code,
        null::text as effect_name,
        'multiple active catalog rows share the same code' as detail
      from public.evd_item_catalog c
     where c.is_active = true
     group by c.code
    having count(*) > 1;
$$;
-- END items/dispatch/evd_validate_item_effect_registry.sql

-- BEGIN functions/internal/evd_generate_floor.sql
create or replace function public.evd_generate_floor(p_profile_id uuid, p_floor_no integer, p_board_size integer default 7)
returns jsonb
language plpgsql
as $$
declare
    v_weights jsonb;
    v_counts jsonb := '{}'::jsonb;
    v_grid jsonb := '[]'::jsonb;
    v_cells text[];
    v_coord text;
    v_parts text[];
    v_row jsonb;
    v_x integer;
    v_y integer;
    v_stairs_x integer;
    v_stairs_y integer;
    v_cell_type text;
    v_cell jsonb;
    v_rule record;
    v_current_count integer;
    v_min_count integer;
    v_max_count integer;
    v_remaining_min integer := 0;
    v_force_min boolean := false;
    v_available_cells integer;
begin
    v_available_cells := (p_board_size * p_board_size) - 2;

    v_stairs_x := floor(random() * p_board_size)::integer;
    v_stairs_y := floor(random() * p_board_size)::integer;
    while v_stairs_x = 3 and v_stairs_y = 3 loop
        v_stairs_x := floor(random() * p_board_size)::integer;
        v_stairs_y := floor(random() * p_board_size)::integer;
    end loop;

    for v_y in 0..(p_board_size - 1) loop
        v_row := '[]'::jsonb;
        for v_x in 0..(p_board_size - 1) loop
            if v_x = 3 and v_y = 3 then
                v_cell_type := '空白';
            elsif v_x = v_stairs_x and v_y = v_stairs_y then
                v_cell_type := '下り階段';
            else
                v_cell_type := '空白';
            end if;

            v_cell := jsonb_build_object(
                'x', v_x,
                'y', v_y,
                'type', v_cell_type,
                'revealed', (v_x = 3 and v_y = 3),
                'visited', (v_x = 3 and v_y = 3),
                'resolved', (v_x = 3 and v_y = 3),
                'hint',
                    case
                        when v_cell_type in ('爆弾', '大爆発') then 'bomb'
                        when v_cell_type in ('罠', '呪い') then 'hazard'
                        else null
                    end
            );
            v_row := v_row || jsonb_build_array(v_cell);
        end loop;
        v_grid := v_grid || jsonb_build_array(v_row);
    end loop;

    select array_agg(format('%s,%s', c.x, c.y) order by random())
      into v_cells
      from (
        select xg as x, yg as y
          from generate_series(0, p_board_size - 1) as xg
          cross join generate_series(0, p_board_size - 1) as yg
         where not (xg = 3 and yg = 3)
           and not (xg = v_stairs_x and yg = v_stairs_y)
      ) c;

    foreach v_coord in array coalesce(v_cells, array[]::text[]) loop
        v_parts := string_to_array(v_coord, ',');
        v_x := coalesce(v_parts[1], '0')::integer;
        v_y := coalesce(v_parts[2], '0')::integer;

        v_remaining_min := 0;
        for v_rule in
            select tile_type, min_count
              from public.evd_floor_tile_weight_profiles
             where profile_id = p_profile_id
               and floor_no = p_floor_no
               and is_enabled = true
               and tile_type <> '下り階段'
        loop
            v_current_count := coalesce((v_counts ->> v_rule.tile_type)::integer, 0);
            v_min_count := greatest(coalesce(v_rule.min_count, 0), 0);
            if v_current_count < v_min_count then
                v_remaining_min := v_remaining_min + (v_min_count - v_current_count);
            end if;
        end loop;

        v_force_min := v_remaining_min > 0;
        v_weights := '{}'::jsonb;

        for v_rule in
            select tile_type, weight, min_count, max_count
              from public.evd_floor_tile_weight_profiles
             where profile_id = p_profile_id
               and floor_no = p_floor_no
               and is_enabled = true
               and tile_type <> '下り階段'
        loop
            v_current_count := coalesce((v_counts ->> v_rule.tile_type)::integer, 0);
            v_min_count := greatest(coalesce(v_rule.min_count, 0), 0);
            v_max_count := coalesce(v_rule.max_count, v_available_cells);
            if v_max_count < v_min_count then
                v_max_count := v_min_count;
            end if;

            if v_current_count >= v_max_count then
                continue;
            end if;
            if v_force_min and v_current_count >= v_min_count then
                continue;
            end if;
            if coalesce(v_rule.weight, 0) <= 0 then
                continue;
            end if;

            v_weights := jsonb_set(
                v_weights,
                array[v_rule.tile_type],
                to_jsonb(v_rule.weight),
                true
            );
        end loop;

        if v_weights = '{}'::jsonb then
            if v_force_min then
                for v_rule in
                    select tile_type, min_count
                      from public.evd_floor_tile_weight_profiles
                     where profile_id = p_profile_id
                       and floor_no = p_floor_no
                       and is_enabled = true
                       and tile_type <> '下り階段'
                loop
                    v_current_count := coalesce((v_counts ->> v_rule.tile_type)::integer, 0);
                    v_min_count := greatest(coalesce(v_rule.min_count, 0), 0);
                    if v_current_count < v_min_count then
                        v_weights := jsonb_set(v_weights, array[v_rule.tile_type], to_jsonb(1), true);
                    end if;
                end loop;
            end if;
            if v_weights = '{}'::jsonb then
                v_weights := jsonb_build_object('空白', 1);
            end if;
        end if;

        v_cell_type := public.evd_pick_weighted(v_weights);
        v_counts := jsonb_set(
            v_counts,
            array[v_cell_type],
            to_jsonb(coalesce((v_counts ->> v_cell_type)::integer, 0) + 1),
            true
        );

        v_cell := jsonb_build_object(
            'x', v_x,
            'y', v_y,
            'type', v_cell_type,
            'revealed', false,
            'visited', false,
            'resolved', false,
            'hint',
                case
                    when v_cell_type in ('爆弾', '大爆発') then 'bomb'
                    when v_cell_type in ('罠', '呪い') then 'hazard'
                    else null
                end
        );
        v_grid := public.evd_set_cell(v_grid, v_x, v_y, v_cell);
    end loop;

    return jsonb_build_object(
        'start_x', 3,
        'start_y', 3,
        'stairs_x', v_stairs_x,
        'stairs_y', v_stairs_y,
        'grid', v_grid,
        'revealed', jsonb_build_array('3,3'),
        'visited', jsonb_build_array('3,3'),
        'floor_status', '探索中'
    );
end;
$$;
-- END functions/internal/evd_generate_floor.sql

-- BEGIN functions/internal/evd_get_floor_value.sql
create or replace function public.evd_get_floor_value(
    p_profile_id uuid,
    p_floor integer,
    p_key text,
    p_numeric boolean default false
)
returns numeric
language plpgsql
as $$
declare
    v_row public.evd_floor_value_profiles%rowtype;
    v_min numeric := 0;
    v_max numeric := 0;
begin
    select *
      into v_row
      from public.evd_floor_value_profiles
     where profile_id = p_profile_id
       and floor_no = p_floor;

    if not found then
        return 0;
    end if;

    case p_key
        when '小銭' then
            v_min := coalesce(v_row.coin_small_min, 0);
            v_max := coalesce(v_row.coin_small_max, 0);
        when '宝箱' then
            v_min := coalesce(v_row.chest_min, 0);
            v_max := coalesce(v_row.chest_max, 0);
        when '財宝箱' then
            v_min := coalesce(v_row.treasure_chest_min, 0);
            v_max := coalesce(v_row.treasure_chest_max, 0);
        when '祝福' then
            v_min := coalesce(v_row.blessing_min, 0);
            v_max := coalesce(v_row.blessing_max, 0);
        when '呪い' then
            v_min := coalesce(v_row.curse_min, 0);
            v_max := coalesce(v_row.curse_max, 0);
        when '罠' then
            v_min := coalesce(v_row.trap_min, 0);
            v_max := coalesce(v_row.trap_max, 0);
        when '祈願符' then
            v_min := coalesce(v_row.jewel_gacha_rate_min, 0);
            v_max := coalesce(v_row.jewel_gacha_rate_max, 0);
        when '満願符' then
            v_min := coalesce(v_row.jewel_mangan_rate_min, 0);
            v_max := coalesce(v_row.jewel_mangan_rate_max, 0);
        else
            return 0;
    end case;

    if p_numeric then
        return round((random() * (v_max - v_min) + v_min)::numeric, 2);
    end if;

    return floor(random() * ((v_max::integer - v_min::integer) + 1) + v_min::integer)::integer;
end;
$$;
-- END functions/internal/evd_get_floor_value.sql

-- BEGIN functions/internal/evd_compute_coin_pickup_bonus.sql
create or replace function public.evd_compute_coin_pickup_bonus(p_inventory jsonb)
returns integer
language plpgsql
as $$
declare
    v_bonus integer := 0;
begin
    select coalesce(sum(src.quantity * coalesce((c.effect_data ->> 'amount')::integer, 0)), 0)
      into v_bonus
      from (
            select
                code,
                greatest(max(items_qty), max(carried_qty)) as quantity
              from (
                    select
                        e.key as code,
                        coalesce((e.value ->> 'quantity')::integer, 0) as items_qty,
                        0 as carried_qty
                      from jsonb_each(coalesce(p_inventory -> 'items', '{}'::jsonb)) e
                    union all
                    select
                        e.key as code,
                        0 as items_qty,
                        coalesce((e.value ->> 'quantity')::integer, 0) as carried_qty
                      from jsonb_each(coalesce(p_inventory -> 'carried_items', '{}'::jsonb)) e
                ) qty
             group by code
           ) src
      join public.evd_item_catalog c on c.code = src.code
     where src.quantity > 0
       and c.effect_data ->> 'effect' = 'add_coin_on_coin_pickup';

    return coalesce(v_bonus, 0);
end;
$$;
-- END functions/internal/evd_compute_coin_pickup_bonus.sql

-- BEGIN functions/internal/evd_draw_pickup_item.sql
create or replace function public.evd_draw_pickup_item()
returns jsonb
language plpgsql
as $$
declare
    v_item record;
begin
    with weighted_pool as (
        select
            code,
            name,
            effect_data ->> 'effect' as effect,
            weight,
            sum(weight) over () as total_weight,
            sum(weight) over (order by sort_order, code) as cumulative_weight
         from public.evd_item_catalog
         where is_active = true
           and weight > 0
    ),
    draw as (
        select random() * coalesce(max(total_weight), 0) as roll
          from weighted_pool
    )
    select wp.code, wp.name, wp.effect
      into v_item
      from weighted_pool wp
      cross join draw d
     where wp.cumulative_weight >= d.roll
     order by wp.cumulative_weight
     limit 1;

    return jsonb_build_object(
        'item_code', v_item.code,
        'item_name', v_item.name,
        'item_effect', v_item.effect
    );
end;
$$;
-- END functions/internal/evd_draw_pickup_item.sql

-- BEGIN functions/internal/evd_generate_shop_offers.sql
create or replace function public.evd_generate_shop_offers(p_run_id uuid, p_shop_type text)
returns jsonb
language sql
as $$
    with run_context as (
        select current_floor, generation_profile_id
          from public.evd_game_runs
         where id = p_run_id
           and user_id = public.evd_current_user_id()
           and status = '進行中'
    ),
    floor_pricing as (
        select coalesce(fbp.shop_price_multiplier, 1.00::numeric) as multiplier
          from run_context rc
          left join public.evd_floor_bonus_profiles fbp
            on fbp.profile_id = rc.generation_profile_id
           and fbp.floor_no = rc.current_floor
    ),
    passive_modifiers as (
        select public.evd_collect_passive_modifiers(public.evd_current_user_id()) as modifiers
    )
    select coalesce(jsonb_agg(jsonb_build_object(
        'code', code,
        'name', name,
        'description', description,
        'price', price,
        'rarity', rarity
    )), '[]'::jsonb)
    from (
        select
            code,
            name,
            description,
            floor(
                base_price
                * coalesce((select multiplier from floor_pricing), 1.00::numeric)
                * greatest(0::numeric, 1 - coalesce(((select modifiers from passive_modifiers) ->> 'shop_discount_rate')::numeric, 0))
            )::integer as price,
            rarity
          from public.evd_item_catalog
         where is_active = true
           and (
                (p_shop_type = 'ショップ' and shop_pool in ('通常', '両方', '通常限定'))
             or (p_shop_type = '限定ショップ' and shop_pool in ('限定', '両方'))
           )
         order by
            case
                when coalesce(weight, 0) > 0 then -ln(greatest(random(), 1e-9)) / weight
                else 1e9 + random()
            end
         limit 3
    ) q;
$$;
-- END functions/internal/evd_generate_shop_offers.sql

-- BEGIN functions/internal/evd_resolve_floor_shift.sql
create or replace function public.evd_resolve_floor_shift(
    p_run_id uuid,
    p_user_id text,
    p_target_floor integer,
    p_status text default '進行中'
)
returns void
language plpgsql
as $$
declare
    v_run public.evd_game_runs%rowtype;
    v_floor_seed jsonb;
    v_bomb_count integer := 0;
    v_has_doom_eye boolean := false;
    v_floor_heal integer := 0;
begin
    select * into v_run from public.evd_game_runs where id = p_run_id and user_id = p_user_id for update;

    if p_status = '転送移動' then
        v_floor_seed := public.evd_generate_floor(v_run.generation_profile_id, p_target_floor, v_run.board_size);
        insert into public.evd_run_floors (
            run_id, user_id, account_name, floor_no, start_x, start_y, stairs_x, stairs_y, grid, revealed, visited, floor_status
        )
        values (
            p_run_id,
            p_user_id,
            v_run.account_name,
            p_target_floor,
            (v_floor_seed ->> 'start_x')::integer,
            (v_floor_seed ->> 'start_y')::integer,
            (v_floor_seed ->> 'stairs_x')::integer,
            (v_floor_seed ->> 'stairs_y')::integer,
            v_floor_seed -> 'grid',
            v_floor_seed -> 'revealed',
            v_floor_seed -> 'visited',
            p_status
        )
        on conflict (run_id, floor_no) do update
           set account_name = excluded.account_name,
               start_x = excluded.start_x,
               start_y = excluded.start_y,
               stairs_x = excluded.stairs_x,
               stairs_y = excluded.stairs_y,
               grid = excluded.grid,
               revealed = excluded.revealed,
               visited = excluded.visited,
               floor_status = excluded.floor_status,
               updated_at = now();
    elsif not exists (
        select 1 from public.evd_run_floors where run_id = p_run_id and floor_no = p_target_floor
    ) then
        v_floor_seed := public.evd_generate_floor(v_run.generation_profile_id, p_target_floor, v_run.board_size);
        insert into public.evd_run_floors (
            run_id, user_id, account_name, floor_no, start_x, start_y, stairs_x, stairs_y, grid, revealed, visited, floor_status
        )
        values (
            p_run_id,
            p_user_id,
            v_run.account_name,
            p_target_floor,
            (v_floor_seed ->> 'start_x')::integer,
            (v_floor_seed ->> 'start_y')::integer,
            (v_floor_seed ->> 'stairs_x')::integer,
            (v_floor_seed ->> 'stairs_y')::integer,
            v_floor_seed -> 'grid',
            v_floor_seed -> 'revealed',
            v_floor_seed -> 'visited',
            p_status
        );
    end if;

    update public.evd_game_runs
       set current_floor = p_target_floor,
           current_x = 3,
           current_y = 3,
           inventory_state = jsonb_set(
                jsonb_set(
                    jsonb_set(
                        jsonb_set(inventory_state, array['flags', 'stairs_known'], 'false'::jsonb, true),
                        array['flags', 'hazards_known'], 'false'::jsonb, true
                    ),
                    array['flags', 'bombs_known'], 'false'::jsonb, true
                ),
                array['pending_resolution'], 'null'::jsonb, true
           ),
           updated_at = now(),
           last_active_at = now(),
           version = version + 1
     where id = p_run_id;

    select coalesce(sum(coalesce((e.value ->> 'quantity')::integer, 0) * coalesce((c.effect_data ->> 'amount')::integer, 0)), 0)
      into v_floor_heal
      from public.evd_game_runs gr
      cross join jsonb_each(coalesce(gr.inventory_state -> 'items', '{}'::jsonb)) e
      join public.evd_item_catalog c
        on c.code = e.key
     where gr.id = p_run_id
       and coalesce((e.value ->> 'quantity')::integer, 0) > 0
       and c.effect_data ->> 'effect' = 'heal_hp_on_floor_advance';

    if coalesce(v_floor_heal, 0) > 0 then
        update public.evd_game_runs
           set life = least(max_life, life + v_floor_heal),
               updated_at = now(),
               last_active_at = now(),
               version = version + 1
         where id = p_run_id;

        perform public.evd_add_log(
            p_run_id,
            p_user_id,
            v_run.account_name,
            p_target_floor,
            '自動発動',
            format('再生の護符の力でライフを %s 回復した。', v_floor_heal),
            jsonb_build_object('effect', 'heal_hp_on_floor_advance', 'amount', v_floor_heal)
        );
    end if;

    select exists (
        select 1
          from public.evd_player_item_stocks st
          join public.evd_item_catalog c on c.code = st.item_code
         where st.user_id = p_user_id
           and st.quantity > 0
           and c.is_active = true
           and c.effect_data ->> 'effect' = 'relic_bomb_radar_always'
    )
      into v_has_doom_eye;

    if coalesce((v_run.inventory_state -> 'items' -> 'bomb_radar' ->> 'quantity')::integer, 0) > 0 or v_has_doom_eye then
        select count(*)
          into v_bomb_count
          from public.evd_run_floors f
          cross join jsonb_array_elements(f.grid) as row_cells(cell_row)
          cross join jsonb_array_elements(row_cells.cell_row) as cell(cell_item)
         where f.run_id = p_run_id
           and f.floor_no = p_target_floor
           and cell.cell_item ->> 'type' in ('爆弾', '大爆発');

        perform public.evd_add_log(
            p_run_id,
            p_user_id,
            v_run.account_name,
            p_target_floor,
            case when v_has_doom_eye then 'レリック効果' else '爆弾レーダー' end,
            case when v_has_doom_eye
                 then format('破滅の魔眼がこの階層の爆弾を暴いた。爆弾は %s 個あるようだ...', v_bomb_count)
                 else format('爆弾レーダーが反応を示した！この階層には爆弾が %s 個あるようだ...', v_bomb_count)
            end,
            jsonb_build_object('bomb_count', v_bomb_count, 'effect', case when v_has_doom_eye then 'relic_bomb_radar_always' else 'bomb_radar' end)
        );
    end if;
end;
$$;
-- END functions/internal/evd_resolve_floor_shift.sql

-- BEGIN functions/internal/evd_try_consume_revival_charm.sql
create or replace function public.evd_try_consume_revival_charm(
    p_run_id uuid,
    p_user_id text,
    p_account_name text,
    p_floor_no integer
)
returns boolean
language plpgsql
as $$
declare
    v_run public.evd_game_runs%rowtype;
    v_revive_hp integer := 1;
begin
    select *
      into v_run
      from public.evd_game_runs
     where id = p_run_id
       and user_id = p_user_id
     for update;

    if not found then
        return false;
    end if;

    if greatest(
        coalesce((v_run.inventory_state -> 'items' -> 'revival_charm' ->> 'quantity')::integer, 0),
        coalesce((v_run.inventory_state -> 'carried_items' -> 'revival_charm' ->> 'quantity')::integer, 0)
    ) <= 0 then
        return false;
    end if;

    select coalesce((effect_data ->> 'revive_hp')::integer, 1)
      into v_revive_hp
      from public.evd_item_catalog
     where code = 'revival_charm';

    update public.evd_game_runs
       set life = greatest(v_revive_hp, 1),
           inventory_state = public.evd_remove_bucket_item(
                public.evd_remove_item(inventory_state, 'revival_charm', 1),
                'carried_items',
                'revival_charm',
                1
           ),
           updated_at = now(),
           last_active_at = now(),
           version = version + 1
     where id = p_run_id;

    perform public.evd_add_log(
        p_run_id,
        p_user_id,
        p_account_name,
        p_floor_no,
        '自動発動',
        format('復活の護符が砕け、LIFE %s で復活した。', greatest(v_revive_hp, 1)),
        jsonb_build_object('effect', 'revive_on_death', 'item_code', 'revival_charm')
    );

    return true;
end;
$$;
-- END functions/internal/evd_try_consume_revival_charm.sql

-- BEGIN functions/internal/evd_start_run_load_context.sql
create or replace function public.evd_start_run_load_context(
    p_user_id text,
    p_carry_items text[] default '{}'
)
returns jsonb
language plpgsql
as $$
declare
    v_profile record;
    v_profile_id uuid;
    v_carry_limit integer := 2;
    v_passive_modifiers jsonb := '{}'::jsonb;
begin
    if exists (
        select 1
          from public.evd_game_runs
         where user_id = p_user_id
           and status = '騾ｲ陦御ｸｭ'
    ) then
        raise exception '進行中のランが既にあります';
    end if;

    select discord_user_id, coins, account_name
      into v_profile
      from public.profiles
     where discord_user_id = p_user_id
     for update;

    if not found then
        raise exception 'プロフィールが見つかりません';
    end if;

    if coalesce(v_profile.coins, 0) < 1000 then
        raise exception 'コインが足りません';
    end if;

    update public.profiles
       set coins = coins - 1000
     where discord_user_id = p_user_id;

    select id
      into v_profile_id
      from public.evd_game_balance_profiles
     where is_active = true
     order by updated_at desc
     limit 1;

    v_passive_modifiers := public.evd_collect_passive_modifiers(p_user_id);
    v_carry_limit := v_carry_limit + coalesce((v_passive_modifiers ->> 'carry_limit_bonus')::integer, 0);

    if array_length(p_carry_items, 1) > v_carry_limit then
        raise exception '持ち込み数は % 個までです', v_carry_limit;
    end if;

    return jsonb_build_object(
        'account_name', v_profile.account_name,
        'profile_id', v_profile_id,
        'carry_limit', v_carry_limit,
        'golden_return_bonus', coalesce((v_passive_modifiers ->> 'return_multiplier_bonus')::numeric, 0),
        'has_doom_eye', coalesce((v_passive_modifiers ->> 'always_bomb_radar')::boolean, false),
        'has_giant_cup', coalesce((v_passive_modifiers ->> 'max_life_bonus')::integer, 0) > 0,
        'passive_modifiers', v_passive_modifiers
    );
end;
$$;
-- END functions/internal/evd_start_run_load_context.sql

-- BEGIN functions/internal/evd_start_run_build_inventory.sql
create or replace function public.evd_start_run_build_inventory(
    p_user_id text,
    p_account_name text,
    p_carry_items text[] default '{}',
    p_passive_modifiers jsonb default '{}'::jsonb
)
returns jsonb
language plpgsql
as $$
declare
    v_inventory jsonb := jsonb_build_object(
        'items', '{}'::jsonb,
        'flags', jsonb_build_object(
            'insurance_active', false,
            'golden_contract_active', false,
            'stairs_known', false,
            'hazards_known', false,
            'bombs_known', false
        ),
        'carried_items', '{}'::jsonb,
        'pending_resolution', null,
        'pending_shop', null
    );
    v_item text;
begin
    update public.evd_player_item_stocks
       set is_set = case
            when item_code = any(coalesce(p_carry_items, '{}'::text[])) then true
            else false
       end,
           account_name = p_account_name,
           updated_at = now()
     where user_id = p_user_id;

    foreach v_item in array p_carry_items loop
        update public.evd_player_item_stocks
           set quantity = quantity - 1,
               account_name = p_account_name,
               updated_at = now()
         where user_id = p_user_id
           and item_code = v_item
           and quantity > 0;

        if not found then
            raise exception '持ち込み在庫が不足しています: %', v_item;
        end if;

        v_inventory := public.evd_dispatch_apply_granted_item(v_inventory, v_item);
    end loop;

    if coalesce((p_passive_modifiers ->> 'max_life_bonus')::integer, 0) > 0 then
        v_inventory := jsonb_set(v_inventory, array['flags', 'relic_giant_cup_active'], 'true'::jsonb, true);
    end if;

    return v_inventory;
end;
$$;
-- END functions/internal/evd_start_run_build_inventory.sql

-- BEGIN functions/internal/evd_start_run_create_initial_floor.sql
create or replace function public.evd_start_run_create_initial_floor(
    p_run_id uuid,
    p_user_id text,
    p_account_name text,
    p_profile_id uuid,
    p_board_size integer default 7
)
returns jsonb
language plpgsql
as $$
declare
    v_floor_seed jsonb;
begin
    v_floor_seed := public.evd_generate_floor(p_profile_id, 1, p_board_size);

    insert into public.evd_run_floors (
        run_id, user_id, account_name, floor_no, start_x, start_y, stairs_x, stairs_y, grid, revealed, visited, floor_status
    )
    values (
        p_run_id,
        p_user_id,
        p_account_name,
        1,
        (v_floor_seed ->> 'start_x')::integer,
        (v_floor_seed ->> 'start_y')::integer,
        (v_floor_seed ->> 'stairs_x')::integer,
        (v_floor_seed ->> 'stairs_y')::integer,
        v_floor_seed -> 'grid',
        v_floor_seed -> 'revealed',
        v_floor_seed -> 'visited',
        '騾ｲ陦御ｸｭ'
    );

    return v_floor_seed;
end;
$$;
-- END functions/internal/evd_start_run_create_initial_floor.sql

-- BEGIN functions/internal/evd_start_run_log.sql
create or replace function public.evd_start_run_log(
    p_run_id uuid,
    p_user_id text,
    p_account_name text,
    p_inventory jsonb,
    p_golden_return_bonus numeric,
    p_has_doom_eye boolean,
    p_floor_seed jsonb,
    p_carry_items text[] default '{}'
)
returns void
language plpgsql
as $$
declare
    v_bomb_count integer := 0;
begin
    perform public.evd_add_log(
        p_run_id,
        p_user_id,
        p_account_name,
        1,
        'プレイ開始',
        '欲望渦巻くダンジョンへ入場した。',
        jsonb_build_object('carry_items', p_carry_items)
    );

    if coalesce((p_inventory -> 'flags' ->> 'relic_giant_cup_active')::boolean, false) then
        perform public.evd_add_log(
            p_run_id,
            p_user_id,
            p_account_name,
            1,
            'レリック効果',
            '巨人の盃の力で最大LIFEが 1 増加した。',
            jsonb_build_object('effect', 'relic_max_life_plus_1')
        );
    end if;

    if coalesce(p_golden_return_bonus, 0) > 0 then
        perform public.evd_add_log(
            p_run_id,
            p_user_id,
            p_account_name,
            1,
            'レリック効果',
            format('黄金の帰路が輝き、持ち帰り倍率が +%s された。', to_char(p_golden_return_bonus, 'FM0.00')),
            jsonb_build_object('effect', 'relic_return_multiplier_plus_0_05', 'bonus', p_golden_return_bonus)
        );
    end if;

    if coalesce((p_inventory -> 'items' -> 'bomb_radar' ->> 'quantity')::integer, 0) > 0 or p_has_doom_eye then
        select count(*)
          into v_bomb_count
          from jsonb_array_elements(p_floor_seed -> 'grid') as row_cells(cell_row)
          cross join jsonb_array_elements(row_cells.cell_row) as cell(cell_item)
         where cell.cell_item ->> 'type' in ('爆弾', '大爆発');

        perform public.evd_add_log(
            p_run_id,
            p_user_id,
            p_account_name,
            1,
            case when p_has_doom_eye then 'レリック効果' else '爆弾レーダー' end,
            case when p_has_doom_eye
                 then format('破滅の魔眼がこの階層の爆弾を暴いた。爆弾は %s 個あるようだ...', v_bomb_count)
                 else format('爆弾レーダーが反応を示した。この階層には爆弾が %s 個あるようだ...', v_bomb_count)
            end,
            jsonb_build_object('bomb_count', v_bomb_count, 'effect', case when p_has_doom_eye then 'relic_bomb_radar_always' else 'bomb_radar' end)
        );
    end if;
end;
$$;
-- END functions/internal/evd_start_run_log.sql

-- BEGIN functions/internal/evd_resolve_move_tile.sql
create or replace function public.evd_resolve_move_tile(
    p_run_id uuid,
    p_tile_type text
)
returns jsonb
language plpgsql
as $$
declare
    v_run public.evd_game_runs%rowtype;
    v_message text := '';
    v_damage integer := 0;
    v_coin_delta integer := 0;
    v_actual_coin_loss integer := 0;
    v_rate_delta numeric := 0;
    v_actual_rate_delta numeric := 0;
    v_new_multiplier numeric := 1;
    v_gacha_gain integer := 0;
    v_mangan_gain integer := 0;
    v_offers jsonb;
    v_item jsonb;
    v_pick_item_code text;
    v_pick_item_name text;
begin
    select *
      into v_run
      from public.evd_game_runs
     where id = p_run_id
     for update;

    if not found then
        raise exception '進行中ランが見つかりません';
    end if;

    case p_tile_type
        when '小銭' then
            v_coin_delta := public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '小銭')::integer;
            v_coin_delta := v_coin_delta + public.evd_compute_coin_pickup_bonus(v_run.inventory_state);
            v_message := format('小銭を拾い、%s コイン獲得した。', v_coin_delta);
        when '宝箱' then
            v_coin_delta := public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '宝箱')::integer;
            v_message := format('宝箱を開けて %s コイン獲得した。', v_coin_delta);
        when '財宝箱' then
            v_coin_delta := public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '財宝箱')::integer;
            v_message := format('財宝箱を開けて %s コイン獲得した。', v_coin_delta);
        when '秘宝箱' then
            update public.evd_game_runs
               set badges_gained = badges_gained + 1
             where id = p_run_id;
            v_message := '秘宝箱を開けて、勲章を 1 個獲得した。';
        when '宝石箱' then
            v_gacha_gain := greatest(0, coalesce(public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '祈願符')::integer, 0));
            v_mangan_gain := greatest(0, coalesce(public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '満願符')::integer, 0));
            update public.evd_game_runs
               set gacha_tickets_gained = gacha_tickets_gained + v_gacha_gain,
                   mangan_tickets_gained = mangan_tickets_gained + v_mangan_gain
             where id = p_run_id;
            v_message := format('宝石箱を開けて祈願符 %s 枚、満願符 %s 枚を獲得した。', v_gacha_gain, v_mangan_gain);
        when 'アイテム' then
            v_item := public.evd_draw_pickup_item();
            v_pick_item_code := nullif(v_item ->> 'item_code', '');
            v_pick_item_name := nullif(v_item ->> 'item_name', '');

            if v_pick_item_code is null then
                v_message := 'アイテムマスだったが、取得できるアイテムが見つからなかった。';
            else
                update public.evd_game_runs
                   set inventory_state = public.evd_dispatch_apply_granted_item(inventory_state, v_pick_item_code)
                 where id = p_run_id;
                v_message := format('%s を入手した。', v_pick_item_name);
            end if;
        when '祝福' then
            v_rate_delta := public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '祝福', true);
            update public.evd_game_runs
               set final_return_multiplier = round((final_return_multiplier + v_rate_delta)::numeric, 2)
             where id = p_run_id
            returning final_return_multiplier into v_new_multiplier;
            v_message := format('祝福を受け、持ち帰り倍率が +%s 上昇して x%s になった。', v_rate_delta, v_new_multiplier);
        when '泉' then
            update public.evd_game_runs
               set life = least(max_life, life + 1)
             where id = p_run_id;
            v_message := '泉の力でライフが 1 回復した。';
        when '爆弾' then
            v_damage := 1;
            v_message := '爆弾が爆発し、ライフを 1 失った。';
        when '大爆発' then
            v_damage := 2;
            v_message := '大爆発に巻き込まれ、ライフを 2 失った。';
        when '呪い' then
            v_coin_delta := -1 * public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '呪い')::integer;
            v_actual_coin_loss := least(abs(v_coin_delta), coalesce(v_run.run_coins, 0));
            v_message := format('呪いを受け、%s コイン失った。', v_actual_coin_loss);
        when '罠' then
            v_rate_delta := public.evd_get_floor_value(v_run.generation_profile_id, v_run.current_floor, '罠', true);
            if v_run.substitute_negates_remaining > 0 then
                update public.evd_game_runs
                   set substitute_negates_remaining = substitute_negates_remaining - 1
                 where id = p_run_id;
                v_message := format('身代わり人形が壊れて %s の悪影響を防いだ。あと %s 回。', p_tile_type, greatest(v_run.substitute_negates_remaining - 1, 0));
            else
                v_new_multiplier := round(greatest(0.30, (v_run.final_return_multiplier - v_rate_delta))::numeric, 2);
                v_actual_rate_delta := round(greatest(0::numeric, v_run.final_return_multiplier - v_new_multiplier)::numeric, 2);
                update public.evd_game_runs
                   set final_return_multiplier = v_new_multiplier
                 where id = p_run_id;
                v_message := format('罠の影響で持ち帰り倍率が -%s 下がり、x%s になった。', to_char(v_actual_rate_delta, 'FM0.00'), to_char(v_new_multiplier, 'FM0.00'));
            end if;
        when 'ショップ' then
            v_offers := public.evd_generate_shop_offers(p_run_id, 'ショップ');
            update public.evd_game_runs
               set inventory_state = jsonb_set(inventory_state, array['pending_shop'], jsonb_build_object('shop_type', 'ショップ', 'offers', v_offers), true)
             where id = p_run_id;
            v_message := '行商人が現れた。品揃えを確認できる。';
        when '限定ショップ' then
            v_offers := public.evd_generate_shop_offers(p_run_id, '限定ショップ');
            update public.evd_game_runs
               set inventory_state = jsonb_set(inventory_state, array['pending_shop'], jsonb_build_object('shop_type', '限定ショップ', 'offers', v_offers), true)
             where id = p_run_id;
            v_message := '限定ショップを見つけた。珍しい品が並んでいる。';
        when '下り階段' then
            v_message := case
                when v_run.current_floor >= v_run.max_floors then '最終階の下り階段に到達した。'
                else '下り階段を見つけた。'
            end;
        else
            v_message := '何も起こらなかった。';
    end case;

    select *
      into v_run
      from public.evd_game_runs
     where id = p_run_id
     for update;

    if v_damage > 0 then
        if v_run.substitute_negates_remaining > 0 then
            update public.evd_game_runs
               set substitute_negates_remaining = substitute_negates_remaining - 1
             where id = p_run_id;
            v_message := format('身代わり人形が壊れて %s のダメージを防いだ。あと %s 回。', p_tile_type, greatest(v_run.substitute_negates_remaining - 1, 0));
        else
            update public.evd_game_runs
               set life = greatest(life - v_damage, 0)
             where id = p_run_id;
        end if;
    end if;

    if v_coin_delta <> 0 then
        if v_run.substitute_negates_remaining > 0 and v_coin_delta < 0 then
            update public.evd_game_runs
               set substitute_negates_remaining = substitute_negates_remaining - 1
             where id = p_run_id;
            v_message := format('身代わり人形が壊れて %s のコイン損失を防いだ。あと %s 回。', p_tile_type, greatest(v_run.substitute_negates_remaining - 1, 0));
        else
            update public.evd_game_runs
               set run_coins = greatest(run_coins + v_coin_delta, 0)
             where id = p_run_id;
        end if;
    end if;

    return jsonb_build_object(
        'message', v_message,
        'item_code', v_pick_item_code,
        'item_name', v_pick_item_name,
        'return_snapshot', false
    );
end;
$$;
-- END functions/internal/evd_resolve_move_tile.sql

-- BEGIN functions/internal/evd_finalize_move.sql
create or replace function public.evd_finalize_move(
    p_run_id uuid,
    p_user_id text,
    p_account_name text,
    p_floor_no integer,
    p_tile_type text,
    p_message text,
    p_item_code text default null,
    p_item_name text default null
)
returns jsonb
language plpgsql
as $$
declare
    v_run public.evd_game_runs%rowtype;
begin
    perform public.evd_add_log(
        p_run_id,
        p_user_id,
        p_account_name,
        p_floor_no,
        '移動イベント',
        p_message,
        jsonb_build_object('tile_type', p_tile_type)
            || case
                when p_tile_type = 'アイテム' and p_item_code is not null then
                    jsonb_build_object('item_code', p_item_code, 'item_name', p_item_name)
                else '{}'::jsonb
            end
    );

    select *
      into v_run
      from public.evd_game_runs
     where id = p_run_id;

    if v_run.life <= 0 then
        if public.evd_try_consume_revival_charm(p_run_id, p_user_id, p_account_name, p_floor_no) then
            return public.evd_build_snapshot(p_run_id, p_user_id);
        end if;

        return public.evd_finish_run(p_run_id, p_user_id, '死亡', '移動イベントでライフが尽きた');
    end if;

    return public.evd_build_snapshot(p_run_id, p_user_id);
end;
$$;
-- END functions/internal/evd_finalize_move.sql

-- BEGIN functions/internal/evd_finish_run_calculate.sql
create or replace function public.evd_finish_run_calculate(
    p_run_id uuid,
    p_user_id text,
    p_status text
)
returns jsonb
language plpgsql
as $$
declare
    v_run public.evd_game_runs%rowtype;
    v_inventory_state jsonb;
    v_items jsonb;
    v_carried_items jsonb;
    v_flags jsonb;
    v_calc jsonb;
    v_payout integer := 0;
    v_has_coffin boolean := false;
begin
    select *
      into v_run
      from public.evd_game_runs
     where id = p_run_id
       and user_id = p_user_id
     for update;

    if not found then
        raise exception '対象のランが見つかりません';
    end if;

    if p_status = '帰還' then
        v_calc := public.evd_dispatch_finish_run_escape_settlement(
            v_run.inventory_state,
            v_run.run_coins,
            v_run.secured_coins,
            v_run.final_return_multiplier
        );
    else
        v_calc := public.evd_dispatch_finish_run_death_settlement(
            p_user_id,
            v_run.inventory_state,
            v_run.run_coins,
            v_run.secured_coins
        );
    end if;

    v_inventory_state := coalesce(v_calc -> 'inventory_state', v_run.inventory_state);
    v_payout := coalesce((v_calc ->> 'payout')::integer, 0);
    v_has_coffin := coalesce((v_calc ->> 'has_coffin')::boolean, false);
    v_items := coalesce(v_inventory_state -> 'items', '{}'::jsonb);
    v_carried_items := coalesce(v_inventory_state -> 'carried_items', '{}'::jsonb);
    v_flags := coalesce(v_inventory_state -> 'flags', '{}'::jsonb);

    return jsonb_build_object(
        'payout', greatest(v_payout, 0),
        'inventory_state', v_inventory_state,
        'items', v_items,
        'carried_items', v_carried_items,
        'flags', v_flags,
        'has_coffin', v_has_coffin,
        'selected_effect', v_calc -> 'selected_effect'
    );
end;
$$;
-- END functions/internal/evd_finish_run_calculate.sql

-- BEGIN functions/internal/evd_finish_run_restore_items.sql
create or replace function public.evd_finish_run_restore_items(
    p_user_id text,
    p_account_name text,
    p_status text,
    p_items jsonb,
    p_carried_items jsonb,
    p_flags jsonb,
    p_has_coffin boolean,
    p_substitute_negates_remaining integer
)
returns jsonb
language plpgsql
as $$
declare
    v_return_item record;
    v_carried_items jsonb := coalesce(p_carried_items, '{}'::jsonb);
begin
    if p_status = '死亡' then
        if coalesce((v_carried_items -> 'substitute_doll' ->> 'quantity')::integer, 0) > 0
           and p_substitute_negates_remaining < 3 then
            v_carried_items := public.evd_remove_bucket_item(jsonb_build_object('carried_items', v_carried_items), 'carried_items', 'substitute_doll', 1) -> 'carried_items';
        end if;

        if coalesce((v_carried_items -> 'insurance_token' ->> 'quantity')::integer, 0) > 0
           and not coalesce((p_flags ->> 'insurance_active')::boolean, false) then
            v_carried_items := public.evd_remove_bucket_item(jsonb_build_object('carried_items', v_carried_items), 'carried_items', 'insurance_token', 1) -> 'carried_items';
        end if;
    end if;

    if p_status = '帰還' then
        for v_return_item in
            select e.key as item_code, coalesce((e.value ->> 'quantity')::integer, 0) as quantity
              from jsonb_each(coalesce(p_items, '{}'::jsonb)) e
              join public.evd_item_catalog c on c.code = e.key
             where coalesce((e.value ->> 'quantity')::integer, 0) > 0
               and (
                    c.item_kind in ('手動', '死亡時', '永続')
                    or c.effect_data ->> 'effect' in ('golden_contract', 'return_multiplier_bonus_on_escape')
               )
        loop
            insert into public.evd_player_item_stocks (user_id, account_name, name, item_code, quantity, is_set, updated_at)
            values (p_user_id, p_account_name, (select c.name from public.evd_item_catalog c where c.code = v_return_item.item_code), v_return_item.item_code, v_return_item.quantity, false, now())
            on conflict (user_id, item_code) do update
            set quantity = public.evd_player_item_stocks.quantity + excluded.quantity,
                account_name = excluded.account_name,
                name = excluded.name,
                updated_at = now();
        end loop;

        for v_return_item in
            select e.key as item_code, coalesce((e.value ->> 'quantity')::integer, 0) as quantity
              from jsonb_each(v_carried_items) e
              join public.evd_item_catalog c on c.code = e.key
             where coalesce((e.value ->> 'quantity')::integer, 0) > 0
               and c.item_kind in ('死亡時', '永続')
        loop
            insert into public.evd_player_item_stocks (user_id, account_name, name, item_code, quantity, is_set, updated_at)
            values (p_user_id, p_account_name, (select c.name from public.evd_item_catalog c where c.code = v_return_item.item_code), v_return_item.item_code, v_return_item.quantity, false, now())
            on conflict (user_id, item_code) do update
            set quantity = public.evd_player_item_stocks.quantity + excluded.quantity,
                account_name = excluded.account_name,
                name = excluded.name,
                updated_at = now();
        end loop;
    else
        if p_has_coffin then
            for v_return_item in
                select e.key as item_code, coalesce((e.value ->> 'quantity')::integer, 0) as quantity
                  from jsonb_each(coalesce(p_items, '{}'::jsonb)) e
                  join public.evd_item_catalog c on c.code = e.key
                 where coalesce((e.value ->> 'quantity')::integer, 0) > 0
                   and c.item_kind = '手動'
            loop
                insert into public.evd_player_item_stocks (user_id, account_name, name, item_code, quantity, is_set, updated_at)
                values (p_user_id, p_account_name, (select c.name from public.evd_item_catalog c where c.code = v_return_item.item_code), v_return_item.item_code, v_return_item.quantity, false, now())
                on conflict (user_id, item_code) do update
                set quantity = public.evd_player_item_stocks.quantity + excluded.quantity,
                    account_name = excluded.account_name,
                    name = excluded.name,
                    updated_at = now();
            end loop;
        end if;

        for v_return_item in
            select e.key as item_code, coalesce((e.value ->> 'quantity')::integer, 0) as quantity
              from jsonb_each(coalesce(p_items, '{}'::jsonb)) e
              join public.evd_item_catalog c on c.code = e.key
             where coalesce((e.value ->> 'quantity')::integer, 0) > 0
               and c.item_kind = '永続'
        loop
            insert into public.evd_player_item_stocks (user_id, account_name, name, item_code, quantity, is_set, updated_at)
            values (p_user_id, p_account_name, (select c.name from public.evd_item_catalog c where c.code = v_return_item.item_code), v_return_item.item_code, v_return_item.quantity, false, now())
            on conflict (user_id, item_code) do update
            set quantity = public.evd_player_item_stocks.quantity + excluded.quantity,
                account_name = excluded.account_name,
                name = excluded.name,
                updated_at = now();
        end loop;

        for v_return_item in
            select e.key as item_code, coalesce((e.value ->> 'quantity')::integer, 0) as quantity
              from jsonb_each(v_carried_items) e
              join public.evd_item_catalog c on c.code = e.key
             where coalesce((e.value ->> 'quantity')::integer, 0) > 0
               and c.item_kind = '永続'
        loop
            insert into public.evd_player_item_stocks (user_id, account_name, name, item_code, quantity, is_set, updated_at)
            values (p_user_id, p_account_name, (select c.name from public.evd_item_catalog c where c.code = v_return_item.item_code), v_return_item.item_code, v_return_item.quantity, false, now())
            on conflict (user_id, item_code) do update
            set quantity = public.evd_player_item_stocks.quantity + excluded.quantity,
                account_name = excluded.account_name,
                name = excluded.name,
                updated_at = now();
        end loop;
    end if;

    return v_carried_items;
end;
$$;
-- END functions/internal/evd_finish_run_restore_items.sql

-- BEGIN functions/internal/evd_finish_run_finalize.sql
create or replace function public.evd_finish_run_finalize(
    p_run_id uuid,
    p_user_id text,
    p_account_name text,
    p_floor_no integer,
    p_status text,
    p_reason text,
    p_payout integer,
    p_inventory_state jsonb
)
returns void
language plpgsql
as $$
begin
    update public.evd_game_runs
       set status = p_status,
           death_reason = p_reason,
           result_payout = greatest(p_payout, 0),
           inventory_state = p_inventory_state,
           ended_at = now(),
           updated_at = now(),
           last_active_at = now(),
           version = version + 1
     where id = p_run_id;

    update public.profiles
       set coins = coalesce(coins, 0) + greatest(p_payout, 0),
           total_assets = coalesce(total_assets, 0) + greatest(p_payout, 0)
     where discord_user_id = p_user_id;

    perform public.evd_add_log(
        p_run_id,
        p_user_id,
        p_account_name,
        p_floor_no,
        case when p_status = '帰還' then '帰還' else '死亡' end,
        case when p_status = '帰還'
             then format('無事に帰還して %s コインを持ち帰った。', p_payout)
             else format('%s。精算結果は %s コインだった。', p_reason, p_payout)
        end,
        jsonb_build_object('payout', p_payout)
    );
end;
$$;
-- END functions/internal/evd_finish_run_finalize.sql

-- BEGIN functions/rpc/evd_set_stock_item_set.sql
create or replace function public.evd_set_stock_item_set(p_item_code text, p_is_set boolean)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_profile record;
    v_item record;
    v_stocks jsonb;
begin
    if v_user_id = '' then
        raise exception 'ログインが必要です';
    end if;

    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    select account_name
      into v_profile
      from public.profiles
     where discord_user_id = v_user_id;

    if not found then
        raise exception 'プロフィールが見つかりません';
    end if;

    select code, name, carry_in_allowed, is_active
      into v_item
      from public.evd_item_catalog
     where code = p_item_code;

    if not found or not v_item.is_active then
        raise exception '対象アイテムが見つかりません';
    end if;

    if not coalesce(v_item.carry_in_allowed, false) then
        raise exception '持ち込み設定できないアイテムです';
    end if;

    update public.evd_player_item_stocks
       set is_set = p_is_set,
           account_name = v_profile.account_name,
           updated_at = now()
     where user_id = v_user_id
       and item_code = p_item_code
       and quantity > 0;

    if not found then
        raise exception '在庫がありません';
    end if;

    select coalesce(jsonb_agg(to_jsonb(s) order by sort_order), '[]'::jsonb)
      into v_stocks
      from (
        select
            st.item_code,
            st.is_set,
            st.quantity,
            st.updated_at,
            jsonb_build_object(
                'name', c.name,
                'description', c.description,
                'item_kind', c.item_kind,
                'base_price', c.base_price,
                'carry_in_allowed', c.carry_in_allowed,
                'shop_pool', c.shop_pool,
                'sort_order', c.sort_order,
                'rarity', c.rarity
            ) as evd_item_catalog,
            c.sort_order
        from public.evd_player_item_stocks st
        join public.evd_item_catalog c on c.code = st.item_code
        where st.user_id = v_user_id
          and st.quantity > 0
      ) s;

    return jsonb_build_object(
        'stocks', v_stocks
    );
end;
$$;
-- END functions/rpc/evd_set_stock_item_set.sql

-- BEGIN functions/rpc/evd_buy_stock_item.sql
create or replace function public.evd_buy_stock_item(p_item_code text)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_profile record;
    v_item record;
    v_stocks jsonb;
    v_price integer := 0;
    v_passive_modifiers jsonb := '{}'::jsonb;
begin
    if v_user_id = '' then
        raise exception 'ログインが必要です';
    end if;

    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    select coins, total_assets, gacha_tickets, mangan_tickets, account_name
      into v_profile
      from public.profiles
     where discord_user_id = v_user_id
     for update;

    if not found then
        raise exception 'プロフィールが見つかりません';
    end if;

    select code, name, description, base_price, shop_pool, is_active, effect_data
      into v_item
      from public.evd_item_catalog
     where code = p_item_code;

    if not found or not v_item.is_active or v_item.shop_pool not in ('通常', '両方', 'レリック') then
        raise exception '購入できないアイテムです';
    end if;

    v_passive_modifiers := public.evd_collect_passive_modifiers(v_user_id);
    v_price := floor(v_item.base_price * greatest(0::numeric, 1 - coalesce((v_passive_modifiers ->> 'shop_discount_rate')::numeric, 0)))::integer;

    if coalesce(v_profile.coins, 0) < v_price then
        raise exception 'コインが足りません';
    end if;

    update public.profiles
       set coins = coins - v_price
     where discord_user_id = v_user_id;

    insert into public.evd_player_item_stocks (user_id, account_name, name, item_code, quantity, is_set, total_purchase_coins, updated_at)
    values (v_user_id, v_profile.account_name, v_item.name, p_item_code, 1, false, v_price, now())
    on conflict (user_id, item_code) do update
    set quantity = public.evd_player_item_stocks.quantity + 1,
        account_name = excluded.account_name,
        name = excluded.name,
        total_purchase_coins = public.evd_player_item_stocks.total_purchase_coins + excluded.total_purchase_coins,
        updated_at = now();

    select coins, total_assets, gacha_tickets, mangan_tickets, account_name
      into v_profile
      from public.profiles
     where discord_user_id = v_user_id;

    select coalesce(jsonb_agg(to_jsonb(s) order by sort_order), '[]'::jsonb)
      into v_stocks
      from (
        select
            st.item_code,
            st.is_set,
            st.quantity,
            st.updated_at,
            jsonb_build_object(
                'name', c.name,
                'description', c.description,
                'item_kind', c.item_kind,
                'base_price', c.base_price,
                'carry_in_allowed', c.carry_in_allowed,
                'shop_pool', c.shop_pool,
                'sort_order', c.sort_order,
                'rarity', c.rarity
            ) as evd_item_catalog,
            c.sort_order
        from public.evd_player_item_stocks st
        join public.evd_item_catalog c on c.code = st.item_code
        where st.user_id = v_user_id
          and st.quantity > 0
      ) s;

    return jsonb_build_object(
        'message', format('%s を %s コインで購入して在庫に追加した。', v_item.name, v_price),
        'profile', to_jsonb(v_profile),
        'stocks', v_stocks
    );
end;
$$;
-- END functions/rpc/evd_buy_stock_item.sql

-- BEGIN functions/rpc/evd_start_run.sql
create or replace function public.evd_start_run(p_carry_items text[] default '{}')
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_run_id uuid;
    v_context jsonb;
    v_profile_id uuid;
    v_account_name text;
    v_floor_seed jsonb;
    v_max_life integer := 3;
    v_inventory jsonb;
    v_initial_return_multiplier numeric(8, 2) := 1.0;
begin
    if v_user_id = '' then
        raise exception 'ログインが必要です';
    end if;

    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    v_context := public.evd_start_run_load_context(v_user_id, p_carry_items);
    v_profile_id := (v_context ->> 'profile_id')::uuid;
    v_account_name := v_context ->> 'account_name';
    v_initial_return_multiplier := round((1.0 + coalesce((v_context ->> 'golden_return_bonus')::numeric, 0))::numeric, 2);

    if coalesce((v_context ->> 'has_giant_cup')::boolean, false) then
        v_max_life := v_max_life + 1;
    end if;

    v_inventory := public.evd_start_run_build_inventory(
        v_user_id,
        v_account_name,
        p_carry_items,
        coalesce(v_context -> 'passive_modifiers', '{}'::jsonb)
    );

    insert into public.evd_game_runs (
        user_id, account_name, generation_profile_id, status, life, max_life, inventory_state, substitute_negates_remaining, final_return_multiplier
    )
    values (
        v_user_id,
        v_account_name,
        v_profile_id,
        '騾ｲ陦御ｸｭ',
        v_max_life,
        v_max_life,
        v_inventory,
        case when coalesce((v_inventory -> 'flags' ->> 'substitute_ready')::boolean, false) then 3 else 0 end,
        v_initial_return_multiplier
    )
    returning id into v_run_id;

    v_floor_seed := public.evd_start_run_create_initial_floor(
        v_run_id,
        v_user_id,
        v_account_name,
        v_profile_id,
        7
    );

    perform public.evd_start_run_log(
        v_run_id,
        v_user_id,
        v_account_name,
        v_inventory,
        coalesce((v_context ->> 'golden_return_bonus')::numeric, 0),
        coalesce((v_context ->> 'has_doom_eye')::boolean, false),
        v_floor_seed,
        p_carry_items
    );

    return public.evd_build_snapshot(v_run_id, v_user_id);
end;
$$;
-- END functions/rpc/evd_start_run.sql

-- BEGIN functions/rpc/evd_finish_run.sql
create or replace function public.evd_finish_run(
    p_run_id uuid,
    p_user_id text,
    p_status text,
    p_reason text
)
returns jsonb
language plpgsql
as $$
declare
    v_run public.evd_game_runs%rowtype;
    v_calc jsonb;
    v_inventory_state jsonb;
    v_items jsonb;
    v_carried_items jsonb;
    v_flags jsonb;
    v_payout integer := 0;
    v_has_coffin boolean := false;
begin
    select * into v_run from public.evd_game_runs where id = p_run_id and user_id = p_user_id for update;
    if not found then
        raise exception 'ランが見つかりません';
    end if;

    if p_status = '死亡' and public.evd_try_consume_revival_charm(p_run_id, p_user_id, v_run.account_name, v_run.current_floor) then
        return public.evd_build_snapshot(p_run_id, p_user_id);
    end if;

    v_calc := public.evd_finish_run_calculate(p_run_id, p_user_id, p_status);
    v_inventory_state := v_calc -> 'inventory_state';
    v_items := coalesce(v_calc -> 'items', '{}'::jsonb);
    v_carried_items := coalesce(v_calc -> 'carried_items', '{}'::jsonb);
    v_flags := coalesce(v_calc -> 'flags', '{}'::jsonb);
    v_payout := coalesce((v_calc ->> 'payout')::integer, 0);
    v_has_coffin := coalesce((v_calc ->> 'has_coffin')::boolean, false);

    v_carried_items := public.evd_finish_run_restore_items(
        p_user_id,
        v_run.account_name,
        p_status,
        v_items,
        v_carried_items,
        v_flags,
        v_has_coffin,
        v_run.substitute_negates_remaining
    );

    v_inventory_state := jsonb_set(v_inventory_state, array['carried_items'], v_carried_items, true);

    perform public.evd_finish_run_finalize(
        p_run_id,
        p_user_id,
        v_run.account_name,
        v_run.current_floor,
        p_status,
        p_reason,
        v_payout,
        v_inventory_state
    );

    return public.evd_build_snapshot(p_run_id, p_user_id);
end;
$$;
-- END functions/rpc/evd_finish_run.sql

-- BEGIN functions/rpc/evd_move.sql
create or replace function public.evd_move(p_run_id uuid, p_direction text)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_run public.evd_game_runs%rowtype;
    v_floor public.evd_run_floors%rowtype;
    v_grid jsonb;
    v_cell jsonb;
    v_next_x integer;
    v_next_y integer;
    v_result jsonb;
begin
    if v_user_id = '' then
        raise exception 'ログインが必要です';
    end if;

    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    select *
      into v_run
      from public.evd_game_runs
     where id = p_run_id
       and user_id = v_user_id
       and status = '進行中'
     for update;

    if not found then
        raise exception '進行中ランが見つかりません';
    end if;

    if coalesce(v_run.inventory_state -> 'pending_shop', 'null'::jsonb) <> 'null'::jsonb then
        raise exception 'ショップの処理を先に完了してください';
    end if;

    select *
      into v_floor
      from public.evd_run_floors
     where run_id = p_run_id
       and floor_no = v_run.current_floor
     for update;

    v_next_x := v_run.current_x + case p_direction when 'left' then -1 when 'right' then 1 else 0 end;
    v_next_y := v_run.current_y + case p_direction when 'up' then -1 when 'down' then 1 else 0 end;

    if v_next_x < 0 or v_next_x >= v_run.board_size or v_next_y < 0 or v_next_y >= v_run.board_size then
        raise exception '移動先が盤面の外です';
    end if;

    v_grid := v_floor.grid;
    v_cell := public.evd_get_cell(v_grid, v_next_x, v_next_y);

    v_cell := jsonb_set(
        jsonb_set(v_cell, array['revealed'], 'true'::jsonb, true),
        array['visited'],
        'true'::jsonb,
        true
    );
    v_grid := public.evd_set_cell(v_grid, v_next_x, v_next_y, v_cell);

    update public.evd_game_runs
       set current_x = v_next_x,
           current_y = v_next_y,
           updated_at = now(),
           last_active_at = now(),
           version = version + 1
     where id = p_run_id;

    update public.evd_run_floors
       set grid = v_grid,
           revealed = case
               when not (v_floor.revealed @> jsonb_build_array(format('%s,%s', v_next_x, v_next_y)))
                   then v_floor.revealed || jsonb_build_array(format('%s,%s', v_next_x, v_next_y))
               else v_floor.revealed
           end,
           visited = case
               when not (v_floor.visited @> jsonb_build_array(format('%s,%s', v_next_x, v_next_y)))
                   then v_floor.visited || jsonb_build_array(format('%s,%s', v_next_x, v_next_y))
               else v_floor.visited
           end,
           updated_at = now()
     where id = v_floor.id;

    if coalesce((v_cell ->> 'resolved')::boolean, false) then
        return public.evd_build_snapshot(p_run_id, v_user_id);
    end if;

    v_result := public.evd_resolve_move_tile(p_run_id, v_cell ->> 'type');

    if coalesce((v_result ->> 'return_snapshot')::boolean, false) then
        return public.evd_build_snapshot(p_run_id, v_user_id);
    end if;

    v_cell := jsonb_set(v_cell, array['resolved'], 'true'::jsonb, true);
    v_grid := public.evd_set_cell(v_grid, v_next_x, v_next_y, v_cell);

    update public.evd_run_floors
       set grid = v_grid
     where id = v_floor.id;

    return public.evd_finalize_move(
        p_run_id,
        v_user_id,
        v_run.account_name,
        v_run.current_floor,
        v_cell ->> 'type',
        coalesce(v_result ->> 'message', ''),
        v_result ->> 'item_code',
        v_result ->> 'item_name'
    );
end;
$$;
-- END functions/rpc/evd_move.sql

-- BEGIN functions/rpc/evd_use_item.sql
create or replace function public.evd_use_item(p_run_id uuid, p_item_code text)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_run public.evd_game_runs%rowtype;
    v_result jsonb;
    v_should_consume boolean := true;
    v_finish_run boolean := false;
    v_finish_status text;
    v_finish_reason text;
begin
    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    select *
      into v_run
      from public.evd_game_runs
     where id = p_run_id
       and user_id = v_user_id
       and status = 'ラン中'
     for update;

    if not found then
        raise exception 'ラン中のランが見つかりません';
    end if;

    if coalesce((v_run.inventory_state -> 'items' -> p_item_code ->> 'quantity')::integer, 0) <= 0 then
        raise exception 'そのアイテムは所持していません';
    end if;

    v_result := public.evd_dispatch_use_item(
        p_run_id,
        v_user_id,
        v_run.account_name,
        v_run.current_floor,
        v_run.max_floors,
        v_run.generation_profile_id,
        p_item_code
    );

    v_should_consume := coalesce((v_result ->> 'should_consume')::boolean, true);
    v_finish_run := coalesce((v_result ->> 'finish_run')::boolean, false);
    v_finish_status := v_result ->> 'finish_status';
    v_finish_reason := v_result ->> 'finish_reason';

    if v_should_consume then
        update public.evd_game_runs
           set inventory_state = public.evd_remove_bucket_item(public.evd_remove_item(inventory_state, p_item_code, 1), 'carried_items', p_item_code, 1),
               updated_at = now(),
               last_active_at = now(),
               version = version + 1
         where id = p_run_id;
    end if;

    if v_finish_run then
        return public.evd_finish_run(p_run_id, v_user_id, v_finish_status, v_finish_reason);
    end if;

    return public.evd_build_snapshot(p_run_id, v_user_id);
end;
$$;
-- END functions/rpc/evd_use_item.sql

-- BEGIN functions/rpc/evd_resolve_stairs.sql
create or replace function public.evd_resolve_stairs(p_run_id uuid, p_action text)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_run public.evd_game_runs%rowtype;
    v_floor public.evd_run_floors%rowtype;
    v_current_cell jsonb;
    v_bonus integer := 0;
    v_target_floor integer;
    v_offers jsonb;
begin
    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    select * into v_run from public.evd_game_runs where id = p_run_id and user_id = v_user_id and status = '進行中' for update;
    if not found then
        raise exception '進行中のランが見つかりません';
    end if;

    select * into v_floor
      from public.evd_run_floors
     where run_id = p_run_id
       and floor_no = v_run.current_floor;

    v_current_cell := public.evd_get_cell(v_floor.grid, v_run.current_x, v_run.current_y);
    if coalesce(v_current_cell ->> 'type', '') <> '下り階段' then
        raise exception '階段の上にいないため選択できません';
    end if;

    if v_run.current_floor >= v_run.max_floors then
        if p_action <> 'return' then
            raise exception '深部の祭壇では帰還のみ選択できます';
        end if;

        with relic_pool as (
            select
                c.code,
                c.name,
                c.description,
                c.rarity,
                c.sort_order,
                greatest(coalesce(c.weight, 0), 1) as effective_weight
              from public.evd_item_catalog c
             where c.is_active = true
               and c.shop_pool = 'レリック'
        )
        select coalesce(
            jsonb_agg(
                jsonb_build_object(
                    'code', picked.code,
                    'name', picked.name,
                    'description', picked.description,
                    'rarity', picked.rarity
                )
                order by picked.sort_order, picked.code
            ),
            '[]'::jsonb
        )
          into v_offers
          from (
            select code, name, description, rarity, sort_order
              from relic_pool
             order by -ln(greatest(random(), 1e-9)) / effective_weight
             limit 2
          ) picked;

        if coalesce(jsonb_array_length(v_offers), 0) = 0 then
            perform public.evd_add_log(p_run_id, v_user_id, v_run.account_name, v_run.current_floor, '帰還', '深部の祭壇を後にして地上へ引き返した。');
            return public.evd_finish_run(p_run_id, v_user_id, '帰還', '深部の祭壇から帰還');
        end if;

        update public.evd_game_runs
           set inventory_state = jsonb_set(inventory_state, array['pending_altar_reward'], jsonb_build_object('offers', v_offers), true)
         where id = p_run_id;

        perform public.evd_add_log(
            p_run_id,
            v_user_id,
            v_run.account_name,
            v_run.current_floor,
            '祭壇報酬',
            '深部の祭壇が輝き、レリックを 1 つ選べるようになった。',
            jsonb_build_object('offers', v_offers)
        );

        return public.evd_build_snapshot(p_run_id, v_user_id);
    end if;

    if p_action = 'return' then
        perform public.evd_add_log(p_run_id, v_user_id, v_run.account_name, v_run.current_floor, '帰還', '階段から地上へ引き返した。');
        return public.evd_finish_run(p_run_id, v_user_id, '帰還', '地上へ帰還');
    end if;

    v_target_floor := v_run.current_floor + 1;
    select coalesce(fbp.bonus_coins, 0)
      into v_bonus
      from public.evd_floor_bonus_profiles fbp
     where fbp.profile_id = v_run.generation_profile_id
       and fbp.floor_no = v_target_floor;

    v_bonus := coalesce(v_bonus, 0);

    update public.evd_game_runs
       set run_coins = run_coins + v_bonus,
           floor_bonus_total = floor_bonus_total + v_bonus
     where id = p_run_id;

    perform public.evd_resolve_floor_shift(p_run_id, v_user_id, v_target_floor, '進行中');
    perform public.evd_add_log(p_run_id, v_user_id, v_run.account_name, v_target_floor, '次階層へ進行', format('%s 階へ進み、到達ボーナス %s コイン獲得した。', v_target_floor, v_bonus));

    return public.evd_build_snapshot(p_run_id, v_user_id);
end;
$$;
-- END functions/rpc/evd_resolve_stairs.sql

-- BEGIN functions/rpc/evd_claim_altar_reward.sql
create or replace function public.evd_claim_altar_reward(p_run_id uuid, p_item_code text)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_run public.evd_game_runs%rowtype;
    v_pending jsonb;
    v_offer jsonb;
    v_item record;
begin
    if v_user_id = '' then
        raise exception 'ログインが必要です';
    end if;

    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    select * into v_run
      from public.evd_game_runs
     where id = p_run_id
       and user_id = v_user_id
       and status = '進行中'
     for update;
    if not found then
        raise exception '進行中のランが見つかりません';
    end if;

    v_pending := coalesce(v_run.inventory_state -> 'pending_altar_reward', 'null'::jsonb);
    if v_pending = 'null'::jsonb then
        raise exception '受け取れる祭壇報酬がありません';
    end if;

    select value
      into v_offer
      from jsonb_array_elements(coalesce(v_pending -> 'offers', '[]'::jsonb)) value
     where value ->> 'code' = p_item_code
     limit 1;

    if v_offer is null then
        raise exception '提示されたレリックから選択してください';
    end if;

    select code, name
      into v_item
      from public.evd_item_catalog
     where code = p_item_code
       and is_active = true
       and shop_pool = 'レリック';

    if not found then
        raise exception '受け取れないレリックです';
    end if;

    update public.evd_game_runs
       set inventory_state = public.evd_add_bucket_item(
            inventory_state - 'pending_altar_reward',
            'carried_items',
            p_item_code,
            1
       )
     where id = p_run_id;

    perform public.evd_add_log(
        p_run_id,
        v_user_id,
        v_run.account_name,
        v_run.current_floor,
        '祭壇報酬',
        format('深部の祭壇から %s を授かった。', v_item.name),
        jsonb_build_object('item_code', p_item_code, 'item_name', v_item.name)
    );

    return public.evd_finish_run(p_run_id, v_user_id, '帰還', '深部の祭壇から帰還');
end;
$$;
-- END functions/rpc/evd_claim_altar_reward.sql

-- BEGIN functions/rpc/evd_shop_purchase.sql
create or replace function public.evd_shop_purchase(p_run_id uuid, p_item_code text)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
    v_user_id text := public.evd_current_user_id();
    v_run public.evd_game_runs%rowtype;
    v_pending jsonb;
    v_offer jsonb;
    v_price integer;
begin
    perform pg_advisory_xact_lock(hashtext('evd:' || v_user_id));

    select * into v_run from public.evd_game_runs where id = p_run_id and user_id = v_user_id and status = '進行中' for update;
    if not found then
        raise exception '進行中のランが見つかりません';
    end if;

    v_pending := v_run.inventory_state -> 'pending_shop';
    if v_pending is null or v_pending = 'null'::jsonb then
        raise exception '利用できるショップがありません';
    end if;

    if p_item_code is null then
        update public.evd_game_runs
           set inventory_state = jsonb_set(inventory_state, array['pending_shop'], 'null'::jsonb, true),
               updated_at = now(),
               last_active_at = now(),
               version = version + 1
         where id = p_run_id;
        perform public.evd_add_log(p_run_id, v_user_id, v_run.account_name, v_run.current_floor, 'ショップ購入', '何も買わず立ち去った。');
        return public.evd_build_snapshot(p_run_id, v_user_id);
    end if;

    select item
      into v_offer
      from jsonb_array_elements(v_pending -> 'offers') as item
     where item ->> 'code' = p_item_code
     limit 1;

    if v_offer is null then
        raise exception 'その商品はありません';
    end if;

    v_price := (v_offer ->> 'price')::integer;
    if v_run.run_coins < v_price then
        raise exception 'コインが足りません';
    end if;

    update public.evd_game_runs
       set run_coins = run_coins - v_price,
           inventory_state = jsonb_set(inventory_state, array['pending_shop'], 'null'::jsonb, true),
           updated_at = now(),
           last_active_at = now(),
           version = version + 1
     where id = p_run_id;

    update public.evd_game_runs
       set inventory_state = public.evd_dispatch_apply_granted_item(inventory_state, p_item_code)
     where id = p_run_id;

    perform public.evd_add_log(
        p_run_id,
        v_user_id,
        v_run.account_name,
        v_run.current_floor,
        case when coalesce(v_pending ->> 'shop_type', 'ショップ') = '限定ショップ' then '限定ショップ購入' else 'ショップ購入' end,
        format('%s を %s コインで購入した。', v_offer ->> 'name', v_price),
        jsonb_build_object('item_code', p_item_code, 'price', v_price)
    );

    return public.evd_build_snapshot(p_run_id, v_user_id);
end;
$$;
-- END functions/rpc/evd_shop_purchase.sql

